"use client";

import { motion } from "framer-motion";

export default function Dashboard() {
  
  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="w-full bg-putty-50 p-8"
    >
      
    </motion.div>
  );
}
